// ---- HLSL Shader Sources (SM5.1, register spaces for SDL3 D3D12 backend) ----
static const char vs_hlsl_source[] =
	"cbuffer VertexUniforms : register(b0, space1) {\n"
	"    float2 screen_size;\n"
	"};\n"
	"struct VSInput {\n"
	"    float2 position : TEXCOORD0;\n"
	"    uint   color    : TEXCOORD1;\n"
	"    float2 texcoord : TEXCOORD2;\n"
	"};\n"
	"struct VSOutput {\n"
	"    float4 position : SV_Position;\n"
	"    float4 color    : TEXCOORD0;\n"
	"    float2 texcoord : TEXCOORD1;\n"
	"};\n"
	"VSOutput main(VSInput input) {\n"
	"    VSOutput output;\n"
	"    output.position = float4(\n"
	"        (input.position.x / screen_size.x) * 2.0 - 1.0,\n"
	"        1.0 - (input.position.y / screen_size.y) * 2.0,\n"
	"        0.0, 1.0);\n"
	"    output.color = float4(\n"
	"        (float)((input.color >> 24) & 0xFF) / 255.0,\n"
	"        (float)((input.color >> 16) & 0xFF) / 255.0,\n"
	"        (float)((input.color >>  8) & 0xFF) / 255.0,\n"
	"        (float)( input.color        & 0xFF) / 255.0);\n"
	"    output.texcoord = input.texcoord;\n"
	"    return output;\n"
	"}\n";

static const char ps_hlsl_source[] =
	"Texture2D tex : register(t0, space2);\n"
	"SamplerState samp : register(s0, space2);\n"
	"struct PSInput {\n"
	"    float4 position : SV_Position;\n"
	"    float4 color    : TEXCOORD0;\n"
	"    float2 texcoord : TEXCOORD1;\n"
	"};\n"
	"float4 main(PSInput input) : SV_Target {\n"
	"    return input.color * tex.Sample(samp, input.texcoord);\n"
	"}\n";

// ---- Shader Compilation ----
static SDL_GPUShader* compile_hlsl_shader(
	SDL_GPUDevice* device, const char* source,
	const char* target, SDL_GPUShaderStage stage,
	Uint32 num_samplers, Uint32 num_uniform_buffers)
{
	ID3DBlob* code = NULL;
	ID3DBlob* errors = NULL;
	HRESULT hr = D3DCompile(source, strlen(source), NULL, NULL, NULL,
		"main", target, 0, 0, &code, &errors);
	if (FAILED(hr)) {
		if (errors) {
			SDL_Log("Shader compile error: %s",
				(const char*)errors->lpVtbl->GetBufferPointer(errors));
			errors->lpVtbl->Release(errors);
		}
		return NULL;
	}
	if (errors) errors->lpVtbl->Release(errors);

	SDL_GPUShaderCreateInfo info = {
		.code = (const Uint8*)code->lpVtbl->GetBufferPointer(code),
		.code_size = code->lpVtbl->GetBufferSize(code),
		.entrypoint = "main",
		.format = SDL_GPU_SHADERFORMAT_DXBC,
		.stage = stage,
		.num_samplers = num_samplers,
		.num_storage_textures = 0,
		.num_storage_buffers = 0,
		.num_uniform_buffers = num_uniform_buffers,
	};
	SDL_GPUShader* shader = SDL_CreateGPUShader(device, &info);
	code->lpVtbl->Release(code);
	return shader;
}

// ---- GPU Texture Upload ----
static SDL_GPUTexture* gpu_upload_texture(SDL_GPUDevice* device,
	const unsigned char* rgba, int w, int h)
{
	SDL_GPUTexture* tex = SDL_CreateGPUTexture(device, &(SDL_GPUTextureCreateInfo){
		.type = SDL_GPU_TEXTURETYPE_2D,
		.format = SDL_GPU_TEXTUREFORMAT_R8G8B8A8_UNORM,
		.usage = SDL_GPU_TEXTUREUSAGE_SAMPLER,
		.width = (Uint32)w, .height = (Uint32)h,
		.layer_count_or_depth = 1, .num_levels = 1,
		.sample_count = SDL_GPU_SAMPLECOUNT_1,
	});
	assert(tex);

	SDL_GPUTransferBuffer* tbuf = SDL_CreateGPUTransferBuffer(device,
		&(SDL_GPUTransferBufferCreateInfo){
			.usage = SDL_GPU_TRANSFERBUFFERUSAGE_UPLOAD,
			.size = (Uint32)(w * h * 4),
		});
	void* mapped = SDL_MapGPUTransferBuffer(device, tbuf, false);
	memcpy(mapped, rgba, w * h * 4);
	SDL_UnmapGPUTransferBuffer(device, tbuf);

	SDL_GPUCommandBuffer* cmd = SDL_AcquireGPUCommandBuffer(device);
	SDL_GPUCopyPass* copy = SDL_BeginGPUCopyPass(cmd);
	SDL_UploadToGPUTexture(copy,
		&(SDL_GPUTextureTransferInfo){
			.transfer_buffer = tbuf,
			.pixels_per_row = (Uint32)w,
			.rows_per_layer = (Uint32)h,
		},
		&(SDL_GPUTextureRegion){
			.texture = tex,
			.w = (Uint32)w, .h = (Uint32)h, .d = 1,
		}, false);
	SDL_EndGPUCopyPass(copy);
	SDL_SubmitGPUCommandBuffer(cmd);
	SDL_ReleaseGPUTransferBuffer(device, tbuf);
	return tex;
}

static SDL_GPUTexture* gpu_upload_alpha_atlas(SDL_GPUDevice* device,
	const unsigned char* bitmap, int w, int h)
{
	unsigned char* rgba = (unsigned char*)malloc(w * h * 4);
	for (int i = 0; i < w * h; i++) {
		rgba[i * 4 + 0] = 255;
		rgba[i * 4 + 1] = 255;
		rgba[i * 4 + 2] = 255;
		rgba[i * 4 + 3] = bitmap[i];
	}
	SDL_GPUTexture* tex = gpu_upload_texture(device, rgba, w, h);
	free(rgba);
	return tex;
}

#define CONCAT(a, b) a##b
#define ITEM(name, num) CONCAT(name, num),

// These must be hard-coded because the preprocessor can't do "offset + 1"
#define GEN_2(n, o0, o1)      ITEM(n, o0) ITEM(n, o1)
#define GEN_4(n, o0, o1, o2, o3) GEN_2(n, o0, o1) GEN_2(n, o2, o3)

// To avoid writing 512 arguments, we use a slightly different "Nested" approach:
#define B000(n, p) ITEM(n, p##0) ITEM(n, p##1) ITEM(n, p##2) ITEM(n, p##3) ITEM(n, p##4) ITEM(n, p##5) ITEM(n, p##6) ITEM(n, p##7)
#define B00(n, p)  B000(n, p##0) B000(n, p##1) B000(n, p##2) B000(n, p##3) B000(n, p##4) B000(n, p##5) B000(n, p##6) B000(n, p##7)

// This will generate items 000 through 511 (formatted as 3 digits to avoid math)
#define GEN_512_SAFE(n) \
    B00(n, 0) B00(n, 1) B00(n, 2) B00(n, 3) B00(n, 4) B00(n, 5) B00(n, 6) B00(n, 7)

