void WSDL_ContextCreate(WSDL_Context* context, unsigned window_width, unsigned window_height)
{
	SDL_Window* window = SDL_CreateWindow("my window", window_width, window_height, SDL_WINDOW_RESIZABLE);
	assert(window);

	SDL_GPUDevice* device = SDL_CreateGPUDevice(SDL_GPU_SHADERFORMAT_DXBC, true, NULL);
	assert(device);

	bool claimed = SDL_ClaimWindowForGPUDevice(device, window);
	assert(claimed);

	SDL_SetGPUSwapchainParameters(device, window,
		SDL_GPU_SWAPCHAINCOMPOSITION_SDR, SDL_GPU_PRESENTMODE_IMMEDIATE);

	// Compile shaders
	SDL_GPUShader* vs = compile_hlsl_shader(device, vs_hlsl_source,
		"vs_5_1", SDL_GPU_SHADERSTAGE_VERTEX, 0, 1);
	SDL_GPUShader* ps = compile_hlsl_shader(device, ps_hlsl_source,
		"ps_5_1", SDL_GPU_SHADERSTAGE_FRAGMENT, 1, 0);
	assert(vs && ps);

	SDL_GPUTextureFormat sc_format = SDL_GetGPUSwapchainTextureFormat(device, window);

	SDL_GPUVertexAttribute vertex_attrs[] = {
		{ .location = 0, .buffer_slot = 0, .format = SDL_GPU_VERTEXELEMENTFORMAT_FLOAT2, .offset = 0  },
		{ .location = 1, .buffer_slot = 0, .format = SDL_GPU_VERTEXELEMENTFORMAT_UINT,   .offset = 8  },
		{ .location = 2, .buffer_slot = 0, .format = SDL_GPU_VERTEXELEMENTFORMAT_FLOAT2, .offset = 12 },
	};
	SDL_GPUVertexBufferDescription vbuf_desc = {
		.slot = 0, .pitch = sizeof(WzVertex), .input_rate = SDL_GPU_VERTEXINPUTRATE_VERTEX,
	};

	SDL_GPUColorTargetDescription color_desc = {
		.format = sc_format,
		.blend_state = {
			.enable_blend = true,
			.src_color_blendfactor = SDL_GPU_BLENDFACTOR_SRC_ALPHA,
			.dst_color_blendfactor = SDL_GPU_BLENDFACTOR_ONE_MINUS_SRC_ALPHA,
			.color_blend_op = SDL_GPU_BLENDOP_ADD,
			.src_alpha_blendfactor = SDL_GPU_BLENDFACTOR_SRC_ALPHA,
			.dst_alpha_blendfactor = SDL_GPU_BLENDFACTOR_ONE_MINUS_SRC_ALPHA,
			.alpha_blend_op = SDL_GPU_BLENDOP_ADD,
		},
	};
	SDL_GPUGraphicsPipeline* pipeline = SDL_CreateGPUGraphicsPipeline(device,
		&(SDL_GPUGraphicsPipelineCreateInfo){
			.vertex_shader = vs, .fragment_shader = ps,
			.vertex_input_state = {
				.vertex_buffer_descriptions = &vbuf_desc, .num_vertex_buffers = 1,
				.vertex_attributes = vertex_attrs, .num_vertex_attributes = 3,
			},
			.primitive_type = SDL_GPU_PRIMITIVETYPE_TRIANGLELIST,
			.rasterizer_state = { .fill_mode = SDL_GPU_FILLMODE_FILL, .cull_mode = SDL_GPU_CULLMODE_NONE },
			.multisample_state = { .sample_count = SDL_GPU_SAMPLECOUNT_1 },
			.target_info = { .color_target_descriptions = &color_desc, .num_color_targets = 1 },
		});
	assert(pipeline);

	SDL_ReleaseGPUShader(device, vs);
	SDL_ReleaseGPUShader(device, ps);

	SDL_GPUSampler* sampler_nearest = SDL_CreateGPUSampler(device,
		&(SDL_GPUSamplerCreateInfo){
			.min_filter = SDL_GPU_FILTER_NEAREST, .mag_filter = SDL_GPU_FILTER_NEAREST,
			.mipmap_mode = SDL_GPU_SAMPLERMIPMAPMODE_NEAREST,
			.address_mode_u = SDL_GPU_SAMPLERADDRESSMODE_CLAMP_TO_EDGE,
			.address_mode_v = SDL_GPU_SAMPLERADDRESSMODE_CLAMP_TO_EDGE,
			.address_mode_w = SDL_GPU_SAMPLERADDRESSMODE_CLAMP_TO_EDGE,
		});
	SDL_GPUSampler* sampler_linear = SDL_CreateGPUSampler(device,
		&(SDL_GPUSamplerCreateInfo){
			.min_filter = SDL_GPU_FILTER_LINEAR, .mag_filter = SDL_GPU_FILTER_LINEAR,
			.mipmap_mode = SDL_GPU_SAMPLERMIPMAPMODE_LINEAR,
			.address_mode_u = SDL_GPU_SAMPLERADDRESSMODE_CLAMP_TO_EDGE,
			.address_mode_v = SDL_GPU_SAMPLERADDRESSMODE_CLAMP_TO_EDGE,
			.address_mode_w = SDL_GPU_SAMPLERADDRESSMODE_CLAMP_TO_EDGE,
		});

	SDL_GPUBuffer* vertex_buffer = SDL_CreateGPUBuffer(device,
		&(SDL_GPUBufferCreateInfo){ .usage = SDL_GPU_BUFFERUSAGE_VERTEX, .size = WZ_MAX_VERTICES * sizeof(WzVertex) });
	SDL_GPUBuffer* index_buffer = SDL_CreateGPUBuffer(device,
		&(SDL_GPUBufferCreateInfo){ .usage = SDL_GPU_BUFFERUSAGE_INDEX, .size = WZ_MAX_INDICES * sizeof(int) });

	SDL_GPUTransferBuffer* transfer_vtx = SDL_CreateGPUTransferBuffer(device,
		&(SDL_GPUTransferBufferCreateInfo){ .usage = SDL_GPU_TRANSFERBUFFERUSAGE_UPLOAD, .size = WZ_MAX_VERTICES * sizeof(WzVertex) });
	SDL_GPUTransferBuffer* transfer_idx = SDL_CreateGPUTransferBuffer(device,
		&(SDL_GPUTransferBufferCreateInfo){ .usage = SDL_GPU_TRANSFERBUFFERUSAGE_UPLOAD, .size = WZ_MAX_INDICES * sizeof(int) });

	unsigned char white_pixel[] = { 255, 255, 255, 255 };
	SDL_GPUTexture* white_texture = gpu_upload_texture(device, white_pixel, 1, 1);

	context->window = window;
	context->gpu_device = device;
	context->pipeline = pipeline;
	context->sampler_nearest = sampler_nearest;
	context->sampler_linear = sampler_linear;
	context->white_texture = white_texture;
	context->vertex_buffer = vertex_buffer;
	context->index_buffer = index_buffer;
	context->transfer_vtx = transfer_vtx;
	context->transfer_idx = transfer_idx;
}

SDL_AppResult SDL_AppInit(void** appstate, int argc, char* argv[])
{
	WSDL_ContextCreate(&gui_window, WINDOW_WIDTH, WINDOW_HEIGHT);

	// Load fonts via wzgui atlas
	wz_set_gui(&gui_window.gui);
	{
		size_t file_size;
		unsigned char* data = (unsigned char*)SDL_LoadFile("C:\\Windows\\Fonts\\Arial.ttf", &file_size);
		if (!data) {
			SDL_Log("Failed to load font: %s", SDL_GetError());
			return SDL_APP_FAILURE;
		}
		wz_font_load(0, data, (unsigned)file_size, 18.0f);
		wz_font_load(1, data, (unsigned)file_size, 28.0f);
		SDL_free(data);

		data = (unsigned char*)SDL_LoadFile("C:\\Windows\\Fonts\\ArialBD.ttf", &file_size);
		if (data) {
			wz_font_load(2, data, (unsigned)file_size, 24.0f);
			SDL_free(data);
		}

		// Pack icons into font 0's atlas before uploading
		wz_create_dropdown_icon();
		wz_pack_icons_into_atlas();

		// Upload atlas textures to GPU
		for (unsigned fi = 0; fi < gui_window.gui.fonts_count; fi++) {
			WzFont* font = &gui_window.gui.fonts[fi];
			SDL_GPUTexture* atlas_tex = gpu_upload_alpha_atlas(gui_window.gpu_device, font->atlas_bitmap, font->atlas_w, font->atlas_h);
			free(font->atlas_bitmap);
			font->atlas_bitmap = NULL;
			wz_font_set_atlas_texture(fi, (WzTexture) { .data = atlas_tex, .w = (float)font->atlas_w, .h = (float)font->atlas_h });
		}

		// Dropdown icon now lives in font 0 atlas (draw code reads atlas UVs directly)
		free(gui_window.gui.dropdown_icon_bitmap);
		gui_window.gui.dropdown_icon_bitmap = NULL;

		// X icon: reference font 0 atlas with sub-region UVs
		{
			WzFont* font = &gui_window.gui.fonts[0];
			gui.x_icon = (WzTexture){
				.data = font->atlas_texture.data,
				.w = 16, .h = 16,
				.src_x = gui_window.gui.x_icon_atlas_x,
				.src_y = gui_window.gui.x_icon_atlas_y,
				.tex_w = (float)font->atlas_w,
				.tex_h = (float)font->atlas_h,
			};
		}
	}

	return SDL_APP_CONTINUE;
}

